INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4297838','Ой, Іванку-Купайлочку','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой, Іванку-Купайлочку,
Знайди синю фіалочку!
Хоч давно в ліску одквітла
Квітка синя ця тендітна,
Може, десь ще у ярочку
Нам зустрінеться привітна.
Під сухим вона листочком
Заховалась непримітна.
Ой, Іванку-Купайлочку,
Знайди синю фіалочку!

Діти:
Ой, Іванку-Купайлочку!
Знайди синю фіалочку!

Іванко:
Вже давно в ліску одквітла
Квітка синя ця тендітна.

Діти:
Може десь ще у ярочку
Виростає непомітна?

Іванко:
Під сухим вона листочком
Заховалася привітна.

Діти:
То чого ж ти, хлопче, ходиш,
Що шукаєш, чого бродиш?

Іванко:
Рву барвінок в логовині.
В нього теж очиці сині.

Діти:
Покажи нам барвіночок!
Ставай з нами у таночок!','[''pisni.org.ua'', ''cat:kupalski'', ''Купальські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4297838'), datetime('now')),datetime('now'));
