INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_429931','Зійшла вже зоря','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Зійшла вже зоря на небозводі,
Проміння ясне на землю шле,
Мудреців зі сходу, царів багатих,
До Вифлеєму вона веде.

Підім за світом ясної зорі,
Де Боже миле лежить Дитя,
В вертепі біднім, в яслах на сіні,
Де спочив Спас наш, Давець життя.

Вже Херувими співають пісню:
"Богові слава, спокій людям,
Що добру волю для Бога мають,
І добре серце носять в грудях".

Земля Юдейська - наша Вкраїна,
Вертеп убогий - наші серця.
Мир їм приносять і щастя неба
Дитятко Боже й Мати свята.

В покорі Духа, в серцях обнові
Спішім зложити й дари свої,
Дитятко Боже, прийми їх, молим,
Прийми, Ісусе, в любві Твоїй.','[''pisni.org.ua'', ''cat:kolyadky'', ''cat:zakarpatski'', ''Колядки'', ''Закарпатські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_429931'), datetime('now')),datetime('now'));
