INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_430','Тихий сон','Музика: А. Алєксандров Слова: Осип Маковей. Виконує: Наталія Кияк, Ольга Аркадьєва','uk','ukraine_before_1917',NULL,NULL,'Пісневир. Молодіжний співаник. Львів 2001','переробка пісні групи "Pet Shop Boys"','Тихий сон по горах ходить,
За рученьку нiчку водить.
I шумлять ліси все тихше,
Сон малих звiрят колише.
Не шуміть, ліси зелені,
Спати йдіть, вітри студені.
Най малята сплять здорові,
Най їм сняться сни чудові.
Аж на небі зазоріє,
Сонце їх малих зогріє.
I зогріє, й поцілує,
I світами помандрує.','[''pisni.org.ua'', ''cat:kolyskovi'', ''Колискові'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_430'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_430','Тихий сон','Тихий сон по горах ходить,
За рученьку нiчку водить.
I шумлять ліси все тихше,
Сон малих звiрят колише.
Не шуміть, ліси зелені,
Спати йдіть, вітри студені.
Най малята сплять здорові,
Най їм сняться сни чудові.
Аж на небі зазоріє,
Сонце їх малих зогріє.
I зогріє, й поцілує,
I світами помандрує.');
