INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4301137','Казковий новий рік','Музика: Анна Олєйнікова Слова: Олександр Кімряк. Виконує: Марія Стоянова','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Дід Мороз сидить у санях,
Їде, їде - от дива!
Бачить - заїнько маленький
Під ялинкою стриба.
На ялинці зірка-зіронька сія,
А ялинка пишна, пишна і жива.

А у зайця вуха довгі,
Він ялиночку стеріг,
І до нього вовчик-братик
З лісу весело прибіг.
Ведмежа із татом
Стали танцювать,
Із бочонка медом
Звірів пригощать.

Рижі білки поспішали
І горіхів принесли,
А їжата на колючках
Несли сушені гриби.
Дід Мороз у колі
Там співа пісні,
Роздає гостинці -
І радіють всі!
Новий рік, гостинці,
І радіють всі!','[''pisni.org.ua'', ''cat:new-year'', ''Пісні про Новий Рік'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4301137'), datetime('now')),datetime('now'));
