INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4301787','Святий Миколай','Музика: Анна Кривута Слова: Анна Кривута. Виконує: Подих весни','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Заснули села і міста, на землю ніч лягає,
Із нетерпінням дітвора чекає Миколая.
І білі коні, наче сніг, несуть його по небу,
Щоб опівночі він прийшов до мене і до тебе!

Приспів:
Святий Миколай приходить у снах,
У рідний наш край по сніжних стежках!
Дарунків несе нам повні мішки
І тихо кладе під подушки!

У кожного серед людей є мрії та бажання,
І у дорослих, і дітей - святкові сподівання.
Співає в небесах зоря, не спи в цю ніч, благаю.
Зустрінем разом ти і я Святого Миколая!

Приспів.

Заснули села і міста, на землю ніч лягає,
Із нетерпінням дітвора чекає Миколая.
І білі коні, наче сніг, несуть його по небу,
Щоб опівночі він прийшов до мене і до тебе!

Приспів. (2)','[''pisni.org.ua'', ''cat:svyatyy-mykolay'', ''Пісні про Святого Миколая'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4301787'), datetime('now')),datetime('now'));
