INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4298787','Моє Сонечко','Музика: Юрій Старчевод Слова: Віталій Міхалевський. Виконує: Юрій Старчевод','uk','ukraine_1991',NULL,NULL,'https://www.facebook.com/yuriy.starchevod','Посилання на пісню: https://soundcloud.com/yurii-starchevod/sonechko.','Йдемо за руку - мене аж обожнюють
Знизу уверх цікавущії очі.
Що мені хочеш промовити, сонечко?
- Татку, на шию я хочу!
Раз! - і ти вища найвищого дерева,
Грається вітер твоїм голосочком.
Хай буде радісним, хай буде впевненим
Твоє майбутнєє, дочко!
Вивчимо віршик про хатку з віконечком,
Гойдалки будем гойдати до ночі.
Що мені хочеш промовити, донечко?
- Стати дорослою хочу!

Приспів:
Серце забилося птахом підстреленим,
Звідкись роса на очах у куточках...
Хай буде радісним, хай буде впевненим
Твоє майбутнєє, дочко!

Сто раз просіється дощик дорогою,
Виросте вишенька в нашім садочку.
Будеш слухняною - станеш дорослою,
Моя малесенька дочко!
Котяться дні і роки диво-колесом -
Справжня красуня! (дай Бог, не наврочу)
Що мені хочеш промовити, золотко?
- Таточку, заміж я хочу!

Приспів. (2)

Йдемо за руку - мене аж обожнюють
Знизу уверх цікавущії очі.
Що мені хочеш промовити, сонечко?
- Діду, на шию я хочу!','[''pisni.org.ua'', ''cat:pro-ditey'', ''Пісні про любов до дітей'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4298787'), datetime('now')),datetime('now'));
