INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_430230','Росте Деревко Тонке й Високе','Українська народна пісня. Виконує: Гуртоправці, Тарас Компаніченко','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Староукраїнські Колядки і Щедрівки: Святе Різдво (Свято Різдва Світа: Свят-Вечір – Коляда)... Щедрий Вечір (Свято Місяця й Прадіда: Новий Рік ― Святі Водорщі)... Великдень... Зелені Свята (Трійця)... Івана Купала... Астральні Жнива... Рокове Коло. Ширша відміна: А в Ліску в Ліску на Жовтім Піску В Чистому Полі Сам Плужок ходить. А всі Святії за Погоничів за Посівачів. А в Ліску в Ліску на Жовтім Піску Гей понад Лужок оре там Плужок Ой на Горі Буйний Вітер віє Росте Деревко Тонке й Високе Листки з приводу цієї Пісні: Українське Свято Воведення 4.12 - Передріздвяний Святочний час. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Бог, Різдво Світа, Дідух і Лицарі. Cвятий Збір, 8 січня: Прадідна доба. Ідеальні Села. Статеві громади. Містика Астральних Жнив. Стежки до листків про Українські традиції. Рокове Коло. Ідея "Різдва" і культурні Лицарі. Різдво, містична постать і культурний добродій. Різдво подумане у народу як уособлення культурної Сили, що принесла народові сільськогосподарські здобутки. Таким уособленням бувають у світовій мітольоґії культурні лицарі. В Українців приявлює такого лицаря Прадід, добродій народу. Таким культурним лицарем, чи Спасителем (Heilbringer), є Св. Микола, а також Український Гаїлковий Див-Ладо (також: "Дід Ладо"), що наладив тай благословив сійбу проса, або Гаїлковий Галілей, що вчив чи помагав при Першій сійбі пшениці.......................... А в Чистім Полі сам Плужок оре А за тим Плужком сам Господь ходе А всі Святії за Погоничів За Погоничів за Посівачів......................... Постать Дідуха і християнські ідеї. Β Українській скомбінованій реліґії Свята Різдва постать Дідуха супроти християнських святовечірніх ідей не разить дисгармонією, а якраз дуже влучно до них достроюється. У Свят-Вечір народження Ісуса Христа стрічає, — по думці народу, — ідеальний Прадід враз з усім Українським народом велику таїнницю Різдва Світа — й свого Творця, а рівночасно й народженого Спасителя. І тоді колишня думка про Прадіда як Добродія і Спасителя народу відживає в ідеї народження Спасителя Ісуса Христа. Й ідея Українська відродження народу в первісній красоті і силі сходиться з християнською. Адже і християнська церква називає Ісуса новим Адамом. Символічний Дідух — сіно — стелиться на Святовечірній стіл та під столом на пам''ятку Прадіда, що перший збирав сіно для худібки, яку навчився плекати, а рівночасно робиться те з пієтизму для маленького Ісуса, лежачого в яслах на сіні та окруженого домашньою худібкою, неначе в первісних обставинах людського життя. Коли велика Українська рідня очікує Прадіда як Небесного Гостя і з ним приходять містичні Астральні Світила, уся тая ідеальна громада віддає спільний поклін Ісусові. Чи може бути краще віддана хвала Богові, по думці такого мрійливого, все посеред поетичних уяв живучого, народу, як Український? Первісне народне поняття Бога. Християнська ідея Ісуса Христа як Богочоловіка і Спасителя уступає в Колядках перед первісним народним поняттям Бога. Тим більше уступає в другу площину мітична постать Дідуха. Постать Господа в Колядках є типовою приявою Бога природних народів: з особистими неозначеними обрисами, але все як уявлення Найвищого Єства і Господа Світа, що людям сприяє і людьми не гордить. Що Господь має бути учасником Святої Вечері, споживати її, заживати Святовечірні напитки, — хочби був Духовим Єством, — це одно другому не протирічить у думках народу, коли пригадаємо собі, що на Свят-Вечір і душі померших приходять та поживають останки Святої Вечері.','Росте Деревко Тонке й Високе

Приспів:
Повій ми повій ми Боже
із своїм Духом по Земли.

В Корінь Глибоке Верхом Кудряве
А на тім Кудрі Сив Сокіл сидить
Ой сидить-сидить далеко глядить
Ой видить-видить на Синє Море
У Синє Море на Чисте Поле

А в Чистім Полі сам Плужок оре
А за тим Плужком сам Господь ходе
А всі Святії за Погоничів
За Погоничів за Посівачів

Божая Мати їсти носила
Їсти носила Бога просила
Оріте Синки та ції Нивки
Будем сіяти Златеє Злото
Та вродиться нам Срібнеє Срібло
Ядрений Колос Жемчужне Зерно','[''pisni.org.ua'', ''cat:dumy'', ''cat:obzhynkovi'', ''Думи'', ''Обжинкові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_430230'), datetime('now')),datetime('now'));
