INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4301735','Веселкова пісня','Музика: Ольга Янушкевич Слова: Марія Ясакова','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'За веселковим, за небокраєм
Хтось на сопілці чарівно грає.
А чи то грає, чи то здається,
Чи пісня лине із мого серця?

Приспів:
Над моїм краєм,
Над моїм містом
Пісня лунає
Голосом чистим!
Пісня злітає
У світ широкий.
Веселка грає
На семи нотах!

В чарівній пісні слова чудові,
Всі кольорові, всі веселкові.
Краплинки сонця у кожнім слові.
Краплинки щастя теж кольорові.

Приспів.

За веселковим, за небокраєм
Срібні дзвіночки хтось розсипає.
На тих дзвіночках веселка грає,
Пісня лунає над рідним краєм.

Приспів.','[''pisni.org.ua'', ''cat:dytyachi'', ''Дитячі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4301735'), datetime('now')),datetime('now'));
