INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_430287','А йак то було с Почітку Сьвіта','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Колядка стародавня: Українське Різдво Світа. Тогди не було Неба ні Землі. Листки з приводу цієї Пісні: Українське Свято Воведення 4.12 - Передріздвяний Святочний час. Стежки до листків про Українські традиції.','А йак то було с Почітку  Сьвіта
Не було тогдьі Неба ньі Земльі
А лишень було Синеє Море
А на тьім Мори ой Два Дубочки
А на тих Дубоньках Два Голубоньки
Два Голубоньки з Неба зьісланьі
З Неба зьісланьі на відпитаньі
Стали радити  як Сьвіт сотворити
Спустьім сьа в Море до самого дна
Віберім собі Синий Каменец
Синий Каменец Синеє Небо
Віберім собі Жоўтий Каменец
Жоўтий Каменец Жоўтайа Земльа
_ _ _ _ _ _ _ _ _ _ _ _ _ _ _ _ _ _','[''pisni.org.ua'', ''cat:shchedrivky'', ''Щедрівки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_430287'), datetime('now')),datetime('now'));
