INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_429981','Добрий Вечір Тобі Пане Господарю Радуйся (2)','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Колядка стародавня: Українське Різдво Світа (Коляда). Ой там виxодило та Три Товариші. Листки з приводу цієї Пісні: Св. Микола 19.12 – Народний речник перед Богом і Прадід. Бог, Різдво Світа, Дідух і Лицарі. Стежки до листків про Українські традиції.','Добрий Вечір Тобі  Пане Господарю - Радуйся!
Приспів: Ой радуйся Земле Світ Новий народився!

Застеляйте Столи та все Килимами - Радуйся!
Накладіть Колачі з Ярої Пшениці - Радуйся!
Xай сяде до столу вся Ваша Родина - Радуйся!
Вся Наша Родина Ненька Україна - Радуйся!

Xай прийдуть до  Xати Три Празники-Гості - Радуйся!

А що перший Празник то Різдво Святеє  - Радуйся!
Приспів: Ой радуйся Земле Світ Божий народився!

А що другий Празник Святеє Василля  - Радуйся!
Приспів: Ой радуйся Земле Рік Новий народився!

А що Третій Празник Святе Водохреща  - Радуйся!
Приспів: Ой радуйся Земле Людям всім Добрий Вечір!','[''pisni.org.ua'', ''cat:kolyadky'', ''Колядки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_429981'), datetime('now')),datetime('now'));
