INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_430030','Над Вифлеємом заблисла зоря','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Над Вифлеємом заблисла зоря,
Ясне світло сипле дугою,
Світам віщує вже кінець горя,
А прихід царства миру, спокою.

Йде за звіздою пастир убогий
Тремтяче серце в нього питає;
Де народився Господь могучий,
Що Йому славу ангел звіщає?

Йде аж зі сходу цар за звіздою
Минає ріки, минає моря,
А серце б''ється із неспокою:
Кому се світить та ясна зоря?

А зоря світить, б''є блиск чудовий,
Горить у світлі стайня убога,
Як знак великий тайни любови
І милосердя для нас у Бога.','[''pisni.org.ua'', ''cat:cerkovni'', ''Церковні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_430030'), datetime('now')),datetime('now'));
