INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_430134','За Горою за Крутою','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Колядка стародавня: Українське Різдво Світа. В Чистому Полі Сам Плужок ходить. Листки з приводу цієї Пісні: Українське Свято Воведення 4.12 - Передріздвяний Святочний час. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Бог, Різдво Світа, Дідух і Лицарі. Стежки до інших листків про Українські традиції.','За Горою за Крутою
Приспів: Щедрий Вечір Добрий Вечір
Добрим людям на Весь-Ве..

Ой там Господь оре Поле
Божа Мати їсти носе
Їсти носить Бога просить
Щоб з Колоска була жменька

А з Сніпочка була мірка
Щедрий Вечір Добрий Вечір
Добрим людям на весь Здоров''я','[''pisni.org.ua'', ''cat:shchedrivky'', ''Щедрівки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_430134'), datetime('now')),datetime('now'));
