INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4303636','Це тільки мрія','Музика: Степан Стельмащук Слова: Марія Потикевич-Заболотна. Виконує: Нескорені','uk','ukr_ssr_1919_1991',NULL,'1952','Рукопис клавіру Степана Стельмащука, надала Богдана Сімович','*У приспіві в оригіналі: "Чи є на світі ще десь країна..." Зміна на: "Чи де найдеся в світі країна..." зроблена з метою замінити важко-вокальне "і" у високому "ля" в партії перших тенорів на вокально зручніші "е", "а". Степан Стельмащук Вірш написала 1952 р. у Воркуті Марієя Потикевич-Заболотна, на музику поклав Степан Стельмащук 29 серпня 1999 р.','Там, де колиска нашого роду,
Там, де з криниці ми пили воду,
Там, де хатина, сніпками шита,   |
Росла калина, соком налита.      | (2)

Приспів:
Це тільки мрія. Дійсність проклята!
Вмирає з нами мова крилата.
Чи є на світі ще десь країна,    |
Щоб так терпіла, як Україна?     | (2)

Цвіт калиновий, райський, пахучий,
Грона-коралі рідні, цілющі,
Лікуйте душу, сніться ночами,    |
Рятуйте серце поміж дротами.     | (2)

Приспів.

Нема спочинку злій хуртовині!
Хочеться вмерти на Україні!
Обняти любий корч калиновий,     |
Крикнути: "Воля! Світе чудовий!" | (2)

Приспів','[''pisni.org.ua'', ''cat:istorychni'', ''cat:pisni-pro-movy'', ''Історичні пісні'', ''Пісні про рідну мову'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4303636'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4303636','Це тільки мрія','Там, де колиска нашого роду,
Там, де з криниці ми пили воду,
Там, де хатина, сніпками шита,   |
