INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4303430','Друга чота, чота крилатих',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Друга чота, чота крилатих,
Перед веде вона всім юнакам!
Вона не любить скарг, ні жалів
І сміло піде навстріч ворогам!

Приспів:
Булава - це провід наш,
Булава для юнаків,
В таборі йде нам так любо час,
Лунає грімко спів!

Чотар-сокіл чоту крилатих
Веде в огонь, у сміливі бої,
Ми - юнаки чоти крилатих,
Відважні, буйні і завзяті всі!

Приспів.

Друга чота, чота крилатих
Поміж юнацтвом всім перед веде!
Хай спів наш грімко залунає,
Хай наша пісня громом загуде!

Приспів.','[''pisni.org.ua'', ''cat:plastovi'', ''Пластові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4303430'), datetime('now')),datetime('now'));
