INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4304185','Війна курва','Музика: Luiku (Луйку) Слова: Luiku (Луйку). Виконує: Luiku (Луйку)','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Постійно повторюється:
Dm, Em7, Dm, Asus4
В приспіві додатково:
F, Gm
Em7     Asus4
0       0
3       3
0       2
2       2
x       0
x       x
Базові ноти:
d, e, d, a
(друга і третя струна зверху)
Розриває ланцюги в душі на ланки,
В ефірі сльози, що волаєш "Отче Наш"!
І в скрині пилом вже припала вишиванка,
Та світ розділений на їхній і на наш.
Сидиш у тамбурі та думаєш як жити,
Від файки очі розтирають до сльози.
Та скільки вже собі могилу можна рити,
Коли чорти плюють на твої образи?
Приспів:
Війна курва!
Гра музика - та не хочу того свята,
Ніби свято, але хочеться кричати, обирати:
Або жити, або вмерти, але я впертий!
Війна курва! І вона вже не де-юре, а де-факто,
Що поробиш, буду битись без антракту,
Обираю - хочу жити та... Хей, давай, набої подавай!
Хей, давай, набої подавай!
Коли є лють у серці - там нема любові.
Та не зважаєш, що в очах пече пісок.
З колін вставали кароокі, чорноброві,
Співали так, що пронизало до кісток.
В кишенях кулі, сигарети та ікони.
Та в соцмережах пару слів і чорний дим.
Заграли струни та задзвонили дзвони.
Це моя хата - то мій Єрусалим!
Приспів.','[''pisni.org.ua'', ''cat:ato'', ''Пісні російсько-української війни та АТО'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4304185'), datetime('now')),datetime('now'));
