INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_431338','Коло Млина Калина','Українська народна пісня. Виконує: Етнографічний хор Гомін','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Гаїлки-Великдень: Українське свято Відродження Світа. Еротика, жарти, забави, загадки: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Кругом Нього зелененько всередині веселенько. Там то Мамко Мельник! Листки з приводу цієї Пісні: Еротичні містерії, тиждень від Катерини 7.12 до Калети. Еротичні містерії, Калета 13.12 - Передріздвяний Святочний час. Стежки до листків про Українські традиції. Наші діди-баби навчили нас співати в такий спосіб. Тепер ми вчимо молодих, бо не всі мають діда-бабу, і не в усіх діди-баби можуть співати. – Той, хто співає.','Коло Млина Калина
Коло Млина Лелю-Полелю Калина

Там Дівчина ходила
Там Дівчина Лелю-Полелю ходила

Цвіт Калини ламала
Цвіт Калини Лелю-Полелю ламала

Тай в Пучечки в''язала
Тай в пучечки Лелю-Полелю в''язала

Тай складала на Візок
Тай складала Лелю-Полелю на Візок

Тай повезла на Торжок
Тай повезла Лелю-Полелю на Торжок

Тай продала за Шажок
Тай продала Лелю-Полелю за Шажок

Тай купила Голубка
Тай купила Лелю-Полелю Голубка

Тай привезла Додому
