INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_430889','Рано рано говорила Яблунька','Українська народна пісня. Виконує: Ніна Матвієнко','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Рай розвився Господь звеселився. Листки з приводу цієї Пісні: Бог, Різдво Світа, Дідух і Лицарі. Українські Свята Різдва Світа і Щедрого Вечора. Староукраїнські релігійні роздуми про Бога: Яблучко. Що означає ім''я "Коляда"? Св. Микола 19.12 – Народний речник перед Богом і Прадід. Стежки до інших листків про Українські традиції.','Рано-рано говорила Яблунька
Із своїми Яблучками рано-рано

Рано-рано ой ви Яблучка Мої
Ви од мене всі розкотитесь рано-рано
Рано-рано я сама й ізостануся
Без гілочок і без листячка і без вас
Мої Яблучка рано-рано

Рано-рано говорила Галочка
Із своїми да Дружечками рано-рано

Рано-рано ой ви Дружечки Мої
Ви й од мене всі розійдетесь рано-рано
Рано-рано ви й од мене всі розійдетесь
Саму мене ізоставите рано-рано

Рано-рано не журися Молода Галочко
Не саму ми покидаємо рано-рано
Рано-рано ой Князеві уручаємо рано-рано
Рано-рано завтра прийдем дай одвідаєм
Да всі разом пообідаєм рано-рано','[''pisni.org.ua'', ''cat:vesilni'', ''Весільні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_430889'), datetime('now')),datetime('now'));
