INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4308083','Чоботи','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Пісні Явдохи Зуїхи / Запис. Гнат Танцюра. Київ: Наукова Думка, 1965. - 812 с.',NULL,'Чи се тії чоботи, що зять дав?
А за ції чоботи дочку взяв.
Приспів:
Ой, чоботи, чоботи ви мої!
Наробили клопоту ви мені.
Повішаю чоботи на кілку,
Сама піду за прачкою по кутку.
Приспів.
А до води чоботи скрипотять,
А від води чоботи капотять.
Приспів.
На річку йшли чоботи — рипали,
А з річки йшли чоботи — хлипали.
Приспів.
А се тії чоботи з козлини,
Забрали мою рідну дитину.
Приспів.
А за тую чортову козлину
Та віддала рідную дитину.
Приспів.
А се тії чоботи, що з бичка,
Чом вони не роблять так, як дочка?
Приспів.
Ой, піду я до комори по муку,
Повішаю чоботи в куточку.
Приспів.
Ой, чоботи, чоботи в куточку,
А хто мені випере сорочку?
Приспів.
Десь не мала донечки ізроду,
Що йду сама поночі по воду.
Приспів.
А се ції чоботи зять купив,
А чом же він гвоздиків не набив?
Приспів.
Ой, мамочко-любочко ви мої,
Будуть же вам гвоздики в голові.
Приспів.
А зять буде дочкою робити,
А я буду в чоботах ходити.
Приспів.','[''pisni.org.ua'', ''cat:vesilni'', ''Весільні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4308083'), datetime('now')),datetime('now'));
