INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_431185','Ой Ти Коте Марку','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Співаймо Світові-Дитині: Колядки, Щедрівки та Колискові © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Колискові: Світові-Дитині. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Ходить Котик по Плоточку. Листки з приводу цієї Пісні: Еротичні містерії, Катерини 7.12 — Передріздвяний Святочний час. Еротичні містерії, Калета 13.12 — Передріздвяний Святочний час. Співаймо Світові-Дитині: Колядки, Щедрівки та Колискові. Стежки до листків про Українські традиції. Висловлювання: Відчути і зрозуміти. Відчути і зрозуміти все те багатство почуття і гадки, краси й сили, яке вложено й заховано в нашій словесній спадщині. Бо ми володіємо в сій спадщині засобами далеко більшими, ніж хто-небудь думає – і ніж думаємо ми самі. Світ не оцінив їх досі відповідно – і се не диво, коли ми самі не свідомі їх властивої ціни й міри. Так, не знаємо їх і не цінимо їх, – тому між іншим, що шкільна практика, яка й досі панує в виучуванні нашої красної словесности, особливо старшої, своїми схоластичними методами відстрашує навіки від безпосередньої знайомости з її пам''ятками своїх виучеників. – Михайло Грушевський.','Ой Ти Коте Марку
Ходиш по Ярмарку
Не торгуєш не купуєш
Тільки робиш сварку

Геть побив Горнятко
Сполохав Курчатко
Вкрав у Баби Кусень Сала
Ще й кричиш що мало    Гармонізований','[''pisni.org.ua'', ''cat:kolyskovi'', ''Колискові'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_431185'), datetime('now')),datetime('now'));
