INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_431436','Засвіти зірко',NULL,'uk','ukraine_before_1917',NULL,NULL,NULL,'*Там звичайно є більше куплетів, але на жаль я їх не знаю! Прошу навіть продовжити те, що я почала і написати цілу колядку. Я приймаю усі претензії!!!','На небозводі дивна річ
З''явився ясний блиск зорі,
Тому не спали цілу ніч ,
При книгах мудреці царі

Приспів:
Засвіти зірко , зірко засвіти !
Любов до Бога розбуди , розбуди !
Допоможи ,допоможи,
Христа знайти ,знайти.
Нас до яскині приведи!

. .  .  .  .  .  .  .  .  .  .  .  . *','[''pisni.org.ua'', ''cat:kolyadky'', ''Колядки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_431436'), datetime('now')),datetime('now'));
