INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_431634','Раз якось на Весні крізь Проміння Ясне','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Чому кажуть, що життя це розп''яття душі на хресті тіла? Пара - любощі: Квітка-Метелик. Весна-Бажання. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Кругом Нього зелененько всередині веселенько. А на тій Вербі Рожеві Квіти. Буде тобі Квітка Красна. До робіт нема сил до молитв нема слів. Листки з приводу цієї Пісні: Коляда і Великдень: Різдво і Відродження Світа. Вербний Тиждень і Шутка. Гаїлковий Білоданчик і Первісний Молодець-Стрілець Українські реліґійні роздуми про Неволю та Спасіння Про Українські назви місяців Марець і Май. Стежки до листків про Українські традиції.','Раз якось на Весні крізь Проміння Ясне
В мою хатку Метелик влетів
І рожеві вуста Він за Квітку прийняв
І до них ніжно ніжно припав

І рожеві вуста Він за Квітку прийняв
І до них ніжно ніжно припав

З того часу тямлю що робити маю
Все сиджу я сама не сама
І все сниться мені той Метелик чудний
І все чується спів Солов''я

І все сниться мені той Метелик чудний
І все чується спів Солов''я

До робіт нема сил до молитв нема слів
Я бліда пред розп''яттям стою
Ох зніміте мені ту одежу сумну
Дайте здійснення мріям моїм

Ох зніміте мені ту одежу сумну
Дайте здійснення мріям моїм','[''pisni.org.ua'', ''cat:halycki'', ''Пісні з Галичини'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_431634'), datetime('now')),datetime('now'));
