INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4315636','Пісня про маму','Музика: Анна Олєйнікова Слова: Лариса Ратич','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Сонечко у гості хоче завітать,
Пісню про матусю будемо співать,
Мама теж дарує промені свої -
Сонечком ласкавим кличемо її!

Приспів:
Знають діти, знають діти:
Мама може все на світі!
Дзвінко й весело співаю
Про матусю я!
Наймудріша, найдобріша,
Найдорожча, наймиліша,
Ще вона - найкрасивіша! -
Матінка моя!

Радісно сміється весняна блакить,
Пісня про матусю високо летить.
Підхопили пісню друзі всі мої,
Мама - друг найкращий, любимо її!

Приспів.','[''pisni.org.ua'', ''cat:dytyachi'', ''cat:pro-batkiv'', ''Дитячі пісні'', ''Пісні про любов до батьків'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4315636'), datetime('now')),datetime('now'));
