INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_431481','Чорноморець, матінко','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'На крилах пісні, Київ, 1966',NULL,'Чорноморець, матінко, Чорноморець
Вивів мене босую, На морозець.        | (2)

