INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_431735','Ой нема Ганнусі найгіршої муки','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002 2. Купальські пісні. Українські народні пісні. Пісенник. Упорядник О. Ю Чебанюк. - К.: Музична Україна, 1989. - 196 с.','Пара - любощі: Правдонька. Обійми. Вибір Пари. Астральні Заручини — Українське містичне Весілля: Різдво Світа / Купала. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Рай розвився Господь звеселився. Івана Купала тай в Воду упала. А я Тобі Серце тоді правду скажу. Прийди-прийди Серденя на Пухові Подушки. А він Тобі скаже коло Тебе ляже. Правой ручкою обняла ще й поцілувала. Буде пригортати правдоньки питати. Були Світилки Яснії Зірки. Листки з приводу цієї Пісні: Українська Астрально-мітольоґічна реліґійна концепція. Українські релігійні роздуми про Бога. Про Свято Івана Купала Стежки до листків про Українські традиції.','Ой нема Ганнусі найгіршої муки
Як попадешся Миколі у руки

А він Тобі скаже коло Тебе ляже
Буде пригортати правдоньки питати

А ти Молоденька коло нього ляжеш
Ти ж йому Серце правдоньки не скажеш

А я Тобі Серце тоді правду скажу
Як Твою руку із своєю зв''яжу','[''pisni.org.ua'', ''cat:kupalski'', ''cat:vesnyanky-hayivky'', ''Купальські пісні'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_431735'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_431735','Ой нема Ганнусі найгіршої муки','Ой нема Ганнусі найгіршої муки
