INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4317434','Вийди, сонечко','Музика: Зоя Красуляк Слова: Зоя Красуляк. Виконує: Маргарита Щерда','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Вийди, вийди, сонечко,
До нас на поріг,
Кинь свої промінчики -
Хай розтане сніг.
Вийди, вийди, сонечко,
Всіх нас обійми,
Подаруй нам щастячко,
Щоб раділи ми!

Приспів:
Щиро пісня луна,
Розквітає весна,
І дарує пісні
І тобі, і мені!
Сонце в небі сія -
Посміхаюся я,
Вся родина моя,
Україна моя!

Співай, співай, пташечко,
Під вікном моїм,
Заспівай ту пісеньку,
Що до серця всім.
Лине наша пісенька
В сині небеса,
А навкруг всміхається
Весняна краса!

Приспів. (2)','[''pisni.org.ua'', ''cat:dytyachi'', ''Дитячі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4317434'), datetime('now')),datetime('now'));
