INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4303333','Мережі','Музика: Михайло Гайворонський Слова: В. Хмара','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Гей, на дубах золотіє листя,
Йде шляхами спомин у намисті...
Павутиння срібні тче на трави,
Хтось нам казку шепче про дні слави...

Хтось волочить скиби по долині...
На хрестах десь кров... І на калині...
І луна десь грає над шляхами,
І сміється сонце над полями...

Гей, чарівні соняшні мережі!
Хтось пісні розсіяв у безмежжі...
Гей, на дубах зололіє листя,
Йде шляхами спомин у намисті...','[''pisni.org.ua'', ''cat:plastovi'', ''Пластові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4303333'), datetime('now')),datetime('now'));
