INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4304735','Птахоподібна','(То не пташина). Музика: Михайло Хома Слова: Михайло Хома. Виконує: DZIDZIO','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'То не пташина,  то не людина,
Тая людина є птахо-подібна...

