INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_431838','Занадився Журавель Журавель','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2002','Пара — любощі: Журавель. Весільна Пісня-Гра (Пісня Перезви). Наспів цієї Пісні є основою четвертої, заключної, частини Української (Малоросійської) 2-ої Симфонії Петра Ілліча Чайковського, де використано й інші Українські наспіви. Еротика, жарти, забави: Катерини –... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... –... Кругом Нього зелененько всередині веселенько. Занадився Журавель до Бабиних Конопель. Був собi Журавель Понад нашу Полонину Журавлі летіли Занадився Журавель Журавель. Листки з приводу цієї Пісні: Еротичні містерії, тиждень від Катерини 7.12 до Калети. Еротичні містерії, Калета 13.12 - Передріздвяний Святочний час. Стежки до інших листків про Українські пісні.','Занадився Журавель-Журавель
До Бабиних Конопель Конопель

Приспів:
Сякий-такий Журавель
Сякий-такий Довгоносий
Сякий-такий Довгоногий
Сякий-такий виступає
Конопельки все щипає

А я тому Журавлю-Журавлю
Дрючком/Києм ноги поломлю-поломлю/переб''ю

Далі:

Оце ж тобі Журавель-Журавель
Не ходи до Конопель-Конопель

Щоб ти більше не літав не літав
Конопельок не щипав не щипав    Фонограма-мінус (mp3)','[''pisni.org.ua'', ''cat:vesilni'', ''cat:zhartivlyvi'', ''Весільні пісні'', ''Жартівливі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_431838'), datetime('now')),datetime('now'));
