INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_432532','Наше Купайло з Верби з Верби (1)','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004 2. Купальські пісні. Українські народні пісні. Пісенник. Упорядник О. Ю Чебанюк. - К.: Музична Україна, 1989. - 196 с.','Пара - любощі: Поцілунки. Гуси-Гречка. Астральні Заручини — Українське містичне Весілля: Різдво Світа / Купала. Закликання Купала. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Рай розвився Господь звеселився. Івана Купала тай в Воду упала. Ой поцілую не боюся. Три Дні писав я і Три Ночі. Милу Дівчину вибирати. Були Світилки Яснії Зірки. Ой слава Богу не журюся. Листки з приводу цієї Пісні: Українські релігійні роздуми про Бога. Про Свято Івана Купала Стежки до листків про Українські традиції.','Наше Купайло з Верби з Верби
А ти Миколо прийди-прийди
Наше Купайло убирати
Милу Дівчину вибирати

Ой там на Йвана на Купала
Там Ластівонька купалася
На Березі  сушилася
А на Миколу дивилася
Ще Рушничків не напряла
А вже Миколу сподобала

Летіли Гуси Білокрилі
Тай у Миколи Гречку з''їли
Біжи Марусю гони Гуси
Цілуй Миколу в самі вуси
Ой поцілую не боюся
Маю Хустинку обітруся

Ой Ти Дівчино Серце Моє
Сподобалося личко Твоє
Не так личенько як Ти сама
Як на Папері мальована
Три Дні писав я і Три Ночі
Поки списав я чорні брови
Сидів-писав аж Три Днівки
Щоб написати чорні брівки

Там за Горою Сучка бреше
А там Микола Кілля теше
Теше Він теше-притинає
І сам до себе промовляє
Ой слава Богу не журюся
Бо у Неділю оженюся
Коли не в цюю то в другую
Візьму Марусю  Молодую','[''pisni.org.ua'', ''cat:kupalski'', ''Купальські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_432532'), datetime('now')),datetime('now'));
