INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_43230','Ми ні про що тоді не говорили...','Музика: Олександр Дащенко Слова: Олександр Дащенко. Виконує: Олександр Дащенко','uk','ukraine_1991',NULL,NULL,'1. Збірник пісень Студентського Братства Львівської політехніки. Львів, 2000. 2. Аудіозапис','Текст і акорди взято із джерела 1. Виправлено і доповнено за джерелом 2. Про варіати тексту: * за джерелом 2; ** за джерелом 1.','Ми ні про що тоді не говорили,
І навіть думка не була одна.
Не відав я, хто тебе окрилив,
А ти не знала, чом щасливий я.*

Приспів:
Вечір добігає до кінця,
Ні, не до кінця, до тої миті,
Коли так дуже хочеш до лиця
Прохололе листя притулити.
І наосліп віднайти в траві
Сонного жука, чи мокрий камінь,
І піти по втишеній землі **
Світ за очі босими ногами.

Двозначний сміх і погляди косі
Ніколи за спиною не відчуєм.
Чому ніхто із нас не перейшов межі?
Бо ми не знали, що вона існує...

Приспів.

Інші варіанти тексту:

*  Не відала я, хто тебе окрилив,
А ти не знав, чом щаслива я.

** Чи пройти по стишеній землі','[''pisni.org.ua'', ''cat:bardivski'', ''Бардівські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_43230'), datetime('now')),datetime('now'));
