INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4326685','Нашим військовим','Музика: Леся Горова Слова: Леся Горова. Виконує: Леся Горова','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Спокій у небі, на суші і в морі
Охороняють наші військові.
У їхніх руках - життя України,
Усі наші долі, майбутнє країни!

Приспів:
Дякуємо Вам за те,
Що ви ночами не спите
І охороняєте народ наш
Від біди!
Дякуємо вам за те,
Що гідно службу несете:
Буде сильна Україна
Сьогодні і завжди!

Як небезпека над нами
Нависне,
Сильніша від зброї -
Любов до Вітчизни!
І будь-який ворог буде тікати,
Як в бій вирушають
Українські солдати.

Приспів.

Ціною життя і власної крові
Свій край захищають
Наші військові.
Між кулями, в небі,
В окопах, у полі,
Ви всі - наша гордість
Й наші герої!

Приспів.

Буде вільна Україна
Сьогодні і завжди!
Наші військові - це наші герої!','[''pisni.org.ua'', ''cat:ato'', ''Пісні російсько-української війни та АТО'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4326685'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4326685','Нашим військовим','Спокій у небі, на суші і в морі
Охороняють наші військові.
У їхніх руках - життя України,
Усі наші долі, майбутнє країни!

Приспів:
Дякуємо Вам за те,
Що ви ночами не спите
І охороняєте народ наш
Від біди!
Дякуємо вам за те,
Що гідно службу несете:
Буде сильна Україна
Сьогодні і завжди!

Як небезпека над нами
Нависне,
Сильніша від зброї -
Любов до Вітчизни!
І будь-який ворог буде тікати,
Як в бій вирушають
Українські солдати.

Приспів.

Ціною життя і власної крові
Свій край захищають
Наші військові.
Між кулями, в небі,
В окопах, у полі,
Ви всі - наша гордість
Й наші герої!

Приспів.

Буде вільна Україна
Сьогодні і завжди!
Наші військові - це наші герої!');
