INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4327030','Україно, вперед!','Музика: Геннадій Желуденко Слова: Геннадій Желуденко. Виконує: Геннадій Желуденко','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Хай гримлять стадіони:
Україно, вперед!
В спринтах і марафонах -
Україно, вперед!
Будуть в нас чемпіони -
Україно, вперед! -
Бо луна безутомно:
Україно, вперед!

Приспів:
На усіх континентів
Суші, в небі й воді
Ми розставим акценти
У спортивній борні!
Тіла й духу міцного
Наші фан і атлет!
Кличе нас Перемога -
Україно, вперед!

Хай скандують трибуни:
Україно, вперед!
Тож по Слави цілунок -
Україно, вперед!
Дай Бог сил і фортуни -
Україно, вперед! -
На звитяжний рахунок!
Україно, вперед!

Приспів.

Речитатив:
Попри прикрі невдачі
Й дошкульні поразки -
Україно, вперед!
Попри підступні удари
Й болісні падіння -
Україно, вперед!
Попри які завгодно
Перепони й перешкоди -
Україно, вперед!
Крізь терня до зірок -
Україно, вперед!
Тільки вперед!
Завжди вперед!

Приспів','[''pisni.org.ua'', ''cat:himny-marshi'', ''Гимни та марші'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4327030'), datetime('now')),datetime('now'));
