INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4328481','Василю','Українська народна пісня. Виконує: Rock-H (Рокаш)','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Пойте хлопці танцьовати, айбо уважайте,
Яка стоїть напереду - тоту облишайте.
Яка стоїть напереду - най буде здорова,
Беріть тоту танцьовати, што коло порога.
Чия вина - материна, што робити не навчила,
Лем красно вбирала тай на танці заганяла.

Приспів:
Василю, Василю не твоя вина,
Што ти не виросла порядна жона.
Василю Василю, чия вто вина,
Што лем ти виросла дівка паранна?..

Бо тота паранна дівка не буде робити,
Лем ся красно намалює, вби її любити.
Начепить собі монистя на біленьку шию,
Бери ти мене, Іване, авадь ти, Василю.

Приспів.','[''pisni.org.ua'', ''cat:lemkivski'', ''Лемківські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4328481'), datetime('now')),datetime('now'));
