INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4331535','Бринить гітара тихо',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис','Мелодія російської туристичної пісні "Изгиб гитары желтой".','Бринить гітара тихо
І жевріє багаття,
А з неба ясні зорі
Зглядаються на нас...
Сідаймо всі до гурту
І заспіваймо, браття, -
Нехай в акорді лине
Легкий вечірній час.

Вітрила напинав нам
Веселий буйний вітер,
Нас заливали хвилі
Могутнього Дніпра...
Прийняв нас тихий берег,
І срібний місяць світить,
А ліс шепоче стиха,
Що спати вже пора.

В небесній круговерті
Дзвенять-сміються зорі,
Поглянемо угору -
Забудемо про все!
Як добре, що ми разом -
У радості і в горі,
А завтра свіжий вітер
Нас далі понесе!','[''pisni.org.ua'', ''cat:manrivni'', ''Пісні на мандрівну тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4331535'), datetime('now')),datetime('now'));
