INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_433030','Ми є з України','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1990','Багатотиражка Дрогобиччини "Галицька зоря" 5 січня 1991 року.','Записано 1990 року від аматорів хору "Відродження" Дрогобицького Товариства української мови "Просвіта" імені Тараса Шевченка.','Ми є з України,
З веселого краю,
Там так гарно сонце сяє,
Наче в Божім раю.

Просимо Тя, Христе,
Просим Тя, Маленький,
Зглянь ся мирно, зглянь ся  щиро
На наш край рідненький.

Зішли йому волю,
Зішли йому долю,
Хай зростає Україна
На широкім полю.

Просимо Тя, Христе,
Дай ся ублагати,
Щоб воскресла Україна,
Наша рідна мати!    Мелодія для одного голосу','[''pisni.org.ua'', ''cat:halycki'', ''cat:suspilno-politychni'', ''Пісні з Галичини'', ''Суспільно-політичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_433030'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_433030','Ми є з України','Ми є з України,
