INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_43287','Розпустили кучері дівчата','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Збірник пісень Студентського Братства Львівської політехніки. Львів, 2000.',NULL,'Розпустили кучері дівчата,
Ще й підвели брови для краси.
Тільки ти роби, як вчила мати,     |
Не обрізуй русої коси.             |

Хай вона росте густа та пишна
Чорнобровим хлопцям на біду.
Я ж тобі, моя чарівна вишне,       |
Сам троянди в коси заплету.        | (2)

Приспів:
Плач, кохана, плач, тебе я розлюбив, |
А може я тебе ніколи не любив.       |

Стану рано вранці до схід сонця,
Назбираю квітів запашних.
Що є краще за дівочі коси,         |
Ще й троянди вплетені у них.       | (2)

Кажуть, всі дівчата однакові,
Та одна у сни мої ввійшла, -*
Полонила серце юнакові,            |
А ключі від свого не дала.         | (2)

Приспів.

Як настане день твого весілля,
Ти розпустиш коси чарівні,**
Ой яка ж ти гарна, моя мила,       |
В косах ти сподобалась мені.       | (2)

Приспів.
*Варіант:
А мені сподобалась одна;

**Варіанти:
Ти розпустиш коси запашні;
Ти розпустиш коси для краси.','[''pisni.org.ua'', ''cat:dances'', ''cat:lirychni'', ''cat:narodni'', ''cat:romansy'', ''cat:waltzes'', ''Пісні до танцю'', ''Пісні про кохання, ліричні'', ''Народні пісні'', ''Романси'', ''Вальси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_43287'), datetime('now')),datetime('now'));
