INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4333030','Ой, летіло помело через наше село','Українська народна пісня. Виконує: Фолькнери','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой летіло помело
Через наше село!
Купайла на Йвана!

Сіло спочивати
На дядьковій хаті!
Купайла на Йвана!

А дядькова хата
Загорілася!
Купайла на Йвана!

А Йванкова голова
Засмалилася!
Купайла на Йвана!

А Марічка з радощами
Носить воду пригорщами!
Купайла на Йвана!

Що погасить, те й займеться,
А Марічка засміється!
Купайла на Йвана!

Ой, хто бачив, ой, хто чув,
Хто у мене сю ніч був?..
Купайла на Йвана!

Була в мене хлопчина
Із карими очима.
Купайла на Йвана!

На купайлі була, | (5)
Сорочку забула!
Купайла на Йвана!

Не піду додому,
Боюся сорому!
Купайла на Йвана!

Загорнусь в солому
Та й піду додому!
Купайла на Йвана!

Ой летіло помело
Через наше село!
Купайла на Йвана!
Купайла на Йвана!
Купайла на Йвана!','[''pisni.org.ua'', ''cat:kupalski'', ''Купальські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4333030'), datetime('now')),datetime('now'));
