INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4333134','Щастя - коли ти не йдеш на війну','Музика: Ірина Доля Слова: Оксана Гривул, Ірина Доля. Виконує: Ірина Красота, Ірина Доля','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Щастя це просто читаєш газету,
Кави й кориці снує аромат,
Я сяду поруч, відкрию галети,
Діти вже сплять, а нам сну ще нема...
Просто ти звик прокидатись о п''ятій,
Просто я звикла чекати дзвінка,
Щастя це просто разом не спати,
Хочеш до кави іще молока?..

Щастя чалапає сонно по хаті,
Вигукне "Тато!" й газету зімне.
Ти нас захопиш в обійми гарячі,
Все буде добре! - Війна промине!
Кожна секунда карбується в серці,
Кожна хвилина дорожча за скарб,
Ранок і кава, сонце сміється,
Повно довкола світла і фарб.

Сонце всміхнулося, в хаті неділя,
Пташка співає - чує весну,
Берці в кутку і не дзвонить будильник,
Щастя - коли ти не йдеш на війну!
Легко торкнуся цілунком до скроні,
Тихо на вушко щось розкажу,
Ангел небесний нас охоронить,
Сон твій сьогодні я бережу!
Щастя - коли ти не йдеш на війну!','[''pisni.org.ua'', ''cat:ato'', ''Пісні російсько-української війни та АТО'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4333134'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4333134','Щастя - коли ти не йдеш на війну','Щастя це просто читаєш газету,
Кави й кориці снує аромат,
Я сяду поруч, відкрию галети,
Діти вже сплять, а нам сну ще нема...
Просто ти звик прокидатись о п''ятій,
Просто я звикла чекати дзвінка,
Щастя це просто разом не спати,
Хочеш до кави іще молока?..

Щастя чалапає сонно по хаті,
Вигукне "Тато!" й газету зімне.
Ти нас захопиш в обійми гарячі,
Все буде добре! - Війна промине!
Кожна секунда карбується в серці,
Кожна хвилина дорожча за скарб,
Ранок і кава, сонце сміється,
Повно довкола світла і фарб.

Сонце всміхнулося, в хаті неділя,
Пташка співає - чує весну,
Берці в кутку і не дзвонить будильник,
Щастя - коли ти не йдеш на війну!
Легко торкнуся цілунком до скроні,
Тихо на вушко щось розкажу,
Ангел небесний нас охоронить,
Сон твій сьогодні я бережу!
Щастя - коли ти не йдеш на війну!');
