INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4327539','Зоріла золота заграва','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1930',NULL,'Уснословесний жанр повстанська пісня Місце побутування смт Запитів, Кам''янка-Бузький район, Львівська область Респондент Максимишин Марія Олексіївна, 1930 р.н. Збирачі Вовчак Андрій, Мартиник Соломія','Зоріла золота заграва,
Здригався світ під звуки сурм -
Широко залунала слава,
Що нам воскресла вже держава,
Що Україна встала з тюрм.

Гоїлись столітнії рани,
Бо не царив вже кволий жах;
Лежали в поросі тирани,
Розірвано важкі кайдани -
Стеливсь в майбутнє вільний шлях.

Негайно! Що це? Що це чути? -
Це знову поїзд диких орд!
Над досвітом прийшлось збагнути
Питання: бути чи не бути
Без війська і своїх кагорт?!

До лету розгорнули крила
Три сотні молодих спартан -
Бо воля блеском їх сліпила
І не страшна ворожа сила,
І не злякались смерті ран.

Народе, йди скажи Вкраїні,
Що ми готові на наказ,
Що ми збудуєм на руїні
Нові святині і твердині -
Як забажають їх від нас.

Що шлях майбутній вкажуть Крути,
Що місто терня - ореол,
Що Україна мусить бути,
Про Україну всім почути, -
Що світу це новий престол!','[''pisni.org.ua'', ''cat:povstanski'', ''Повстанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4327539'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4327539','Зоріла золота заграва','Зоріла золота заграва,
Здригався світ під звуки сурм -
Широко залунала слава,
Що нам воскресла вже держава,
Що Україна встала з тюрм.

Гоїлись столітнії рани,
Бо не царив вже кволий жах;
Лежали в поросі тирани,
Розірвано важкі кайдани -
Стеливсь в майбутнє вільний шлях.

Негайно! Що це? Що це чути? -
Це знову поїзд диких орд!
Над досвітом прийшлось збагнути
Питання: бути чи не бути
Без війська і своїх кагорт?!

До лету розгорнули крила
Три сотні молодих спартан -
Бо воля блеском їх сліпила
І не страшна ворожа сила,
І не злякались смерті ран.

Народе, йди скажи Вкраїні,
Що ми готові на наказ,
Що ми збудуєм на руїні
Нові святині і твердині -
Як забажають їх від нас.

Що шлях майбутній вкажуть Крути,
Що місто терня - ореол,
Що Україна мусить бути,
Про Україну всім почути, -
Що світу це новий престол!');
