INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4334032','Не моя!..','Музика: Kozak System Слова: Василь Симоненко, Олександр Положинський. Виконує: Kozak System','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','Підбір акордів VovaRko.','Em
Ну скажи, хіба не фантастично,
G
Що у цьому хаосі доріг
Am
Під суворим небом, небом вічним,
H7
Я тебе зустрів і не зберіг?..
