INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4333939','Пісня Діда Мороза','Музика: Сергій Родько Слова: Алла Бінцаровська','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Білий снігу, сніженьку,
Простели доріженьку
Від хати до хати
Новий рік стрічати!

Дід Мороз з торбиною
Йде уже стежиною,
В українськім краї
Він усіх вітає!

