INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4335389','Сестра','Музика: Наталія Май Слова: Наталія Май','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Є у сонця промені ясні,
А у неба - хмари білі-білі,
Дуже поталанило мені -
Є сестричка в мене дуже мила!

Приспів:
Наче янгол, що з небес злетів,
Оберігом маминим сповитий,
Добре серце, руки золоті -
То сестра моя, найкраща в світі!

Є у ночі зорі золоті,
Що до ранку падають в криниці,
Ти, сестричко, зіркою світи,
До людей неси душі скарбницю!

Приспів.

Речитатив:
Сестричко моя люба,
Сестричко рідна моя,
Нехай усі стежинку
В твоєму житті
Будуть благословенні!
Лишайся такою ж доброю
І світлою, як ти є!
Я дуже люблю тебе!

Приспів.','[''pisni.org.ua'', ''cat:devoted'', ''Пісні присвячені окремим особам'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4335389'), datetime('now')),datetime('now'));
