INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_433736','Нова радість світу ся з’явила',NULL,'uk','ukraine_1991',NULL,NULL,NULL,NULL,'Нова радість світу ся з''явила:
Пречиста Діва Сина породила            | (2)

Во Вифлеємі-місті вельми рано
Вітати Пана пастирям сказано.          | (2)

Звізда услугу тую відправляла!
Царів персидських к Ньому проводжала.  | (2)

Принесли Йому миро, ливан, злато.
Взяли заплату небесную за то.

Ірод злосливий з того засмутився,
Що Цар предвічний на світ народився.

Казав воїнам повсюди шукати,
В пень отрочата дволітні стинати.

Йосиф старець Марію забирає
І до Єгипту з Христом утікає.

Нехай же Ірод вічно погибає!
Наш Цар рож денний всіх нас потішає.

Ми нині о Нім гойно веселімся.
Рождеству Його низько поклонімося,

Щоби нам зволив щасливий вік дати,
А по смерти з Ним в небі царствувати.','[''pisni.org.ua'', ''cat:cerkovni'', ''Церковні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_433736'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_433736','Нова радість світу ся з’явила','Нова радість світу ся з''явила:
Пречиста Діва Сина породила            | (2)

Во Вифлеємі-місті вельми рано
Вітати Пана пастирям сказано.          | (2)

Звізда услугу тую відправляла!
Царів персидських к Ньому проводжала.  | (2)

Принесли Йому миро, ливан, злато.
Взяли заплату небесную за то.

Ірод злосливий з того засмутився,
Що Цар предвічний на світ народився.

Казав воїнам повсюди шукати,
В пень отрочата дволітні стинати.

Йосиф старець Марію забирає
І до Єгипту з Христом утікає.

Нехай же Ірод вічно погибає!
Наш Цар рож денний всіх нас потішає.

Ми нині о Нім гойно веселімся.
