INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_433636','Львів','Музика: M. Hemar Слова: M. Hemar. Виконує: Піккардійська Терція','uk','ukr_ssr_1919_1991',NULL,'1926','Альбом "Піккардійської терції" - "Ельдорадо"','Wyk. Michał Bajor (1926) Аранжування - В.Якимець. Ударні - О.Крупей.','Трудиться вигнане серце
В пошуках твоїх снів
О місто людей веселих
І добрих співучих слів

У ратуші леви камінні
Варту при брамі несуть
Знають вони що незмінні
Юні мрії і цвіт бузку

З зелених садів
Лине цей спів
Бути молодим - то у Львові
Всюди панує слушна оказія
Для веселощів сліз для безсоння й фантазій
Як в небі звізд
Стільки є міст
Та знайдуть ці слова тебе знову
Йди де бажаєш
Чини все так як знаєш
Хочеш в молодість знов - їдь до Львова.

Музика грає
Серце стискає
Щастя хочеш - вернися до Львова
Всюди панує слушна оказія
Для веселощів,сліз,для безсоння й фантазій
Стільки є міст,
Як в небі звізд
Час позначив нас срібним покровом,
Йди, де бажаєш,
Чини все так як знаєш
Хочеш в молодість знов - їдь до Львова','[''pisni.org.ua'', ''cat:lviv'', ''Пісні про Львів'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_433636'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_433636','Львів','Трудиться вигнане серце
В пошуках твоїх снів
