INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4332838','Дитинство не втрачай','Музика: Тіна Кароль Слова: Тіна Кароль, Микола Бровченко. Виконує: Тіна Кароль','uk','ukraine_1991',NULL,NULL,'https://www.youtube.com/watch?v=cgBe00zvwA4 "Відео, кліпи"',NULL,'Дитинство йде від нас кудись,
Тікає швидко босоніж -
І сліду не знайти...
Та нещодавно зовсім ми
Були маленькими людьми
І звалися дітьми!

Приспів:
Там щирі надії,
Там здійснені мрії,
Чекай, дитинство,
Не зникай!
Там друзів багато,
Там мама і тато,
Чекай, дитинство
Не втрачай!

Дитинство поряд недалеко,
Але несуть його лелеки
В край, де нас нема...
Воно зникає, але ми
Завжди лишаємось дітьми,
Мрійливими дітьми!

Приспів.

Що сумно на душі -
Мрії всі свої згадай,
Дитинство не втрачай!
Навколо світ зміни
І собі повір ти!
Дитинство не втрачай!
Дитинство не втрачай!

Дитинство поряд,
Дитинство поряд,
Недалеко, але несуть,
Але несуть його лелеки -
Воно зникає,
Воно зникає, але ми
Завжди лишаємось,
Завжди лишаємось дітьми!..

Приспів.','[''pisni.org.ua'', ''cat:nostalgia'', ''Пісні з ностальгічними мотивами'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4332838'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4332838','Дитинство не втрачай','Дитинство йде від нас кудись,
Тікає швидко босоніж -
І сліду не знайти...
Та нещодавно зовсім ми
Були маленькими людьми
І звалися дітьми!

Приспів:
Там щирі надії,
Там здійснені мрії,
Чекай, дитинство,
Не зникай!
Там друзів багато,
Там мама і тато,
Чекай, дитинство
Не втрачай!

Дитинство поряд недалеко,
Але несуть його лелеки
В край, де нас нема...
Воно зникає, але ми
Завжди лишаємось дітьми,
Мрійливими дітьми!

Приспів.

Що сумно на душі -
Мрії всі свої згадай,
Дитинство не втрачай!
Навколо світ зміни
І собі повір ти!
Дитинство не втрачай!
Дитинство не втрачай!

Дитинство поряд,
Дитинство поряд,
Недалеко, але несуть,
Але несуть його лелеки -
Воно зникає,
Воно зникає, але ми
Завжди лишаємось,
Завжди лишаємось дітьми!..

Приспів.');
