INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4337735','Над студеним джерелом','Музика: Роман Іваненко Слова: Валентина Полинок. Виконує: Інесса Бурдейна','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Над студеним джерелом,
Дощовий прибій,
Збережи моє тепло
У прихистку мрій.
Понад плай, суничний дух,
Чебрецевий час
І цілунків ніжний пух,
Що світає в нас!

Приспів:
Збережи слова мої    |
В сонячному сні!     |
Стануть голосом зорі |
Співані пісні...     | (2)

Щось візьму в далеку путь,
Щось тобі лишу -
Цвіт ромену віщу суть,
Килим споришу,
Гордий затишок лісів,
Зірку полонин
З неосяжної краси
Цих гірських вершин!

Приспів','[''pisni.org.ua'', ''cat:romansy'', ''Романси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4337735'), datetime('now')),datetime('now'));
