INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4293981','Свято Миколая','Музика: Анатолій Салогуб Слова: Анатолій Салогуб. Виконує: Анатолій Салогуб','uk','ukraine_1991',NULL,NULL,'Авторське подання. Анатолій Салогуб',NULL,'Приберу гарненько хату,
Бо приходить в гості свято.
Діти всі його чекають,
Під подушку заглядають,
Миколая прийде свято.

Сяє вже моя хатина,
Спати йде моя родина,
Тільки я не буду спати,
Буду я всю ніч чекати,
Миколая виглядати.

Оченята вже стомились
У віконечко дивитись.
Краще ляжу я у ліжко,
Подрімаю, зовсім трішки,
Щось немає Миколая.

Вранці швидко я схопився,
Під подушку подивився,
Подаруночок до свята
Вже чекає мене радо
Від Святого Миколая','[''pisni.org.ua'', ''cat:svyatyy-mykolay'', ''Пісні про Святого Миколая'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4293981'), datetime('now')),datetime('now'));
