INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4338434','Я не втомився','Музика: Христина Панасюк, Сергій Присяжний Слова: Христина Панасюк, Сергій Присяжний. Виконує: Христина Панасюк, Сергій Присяжний','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Я не спав шість ночей,
Руки стерпли від болю,
А в думках лиш на мить
Вириваюсь на волю...
Я забув про брехню,
Про чиюсь бездіяльність,
Знову град прилетів,
Повернув у реальність...
Третю зиму вогню
Нам війна гарантує,
На своєму шляху
Все безжально руйнує...
А я мовчки роблю
Те, що маю робити,
Бо це наша земля!
Моїм дітям тут жити!

Приспів:
Я не втомився! Сили я маю!      |
Я ворогів у твій дім не пускаю! |
Наче два різні світи,           |
Я не втомився, а ти?..          | (2)

Я не спав шість ночей,
А думки полетіли
До дітей, що для нас
Обереги зробили,
До жінок, що в молитві
Проплакали очі,
І за стукіт сердець,
Що в надії тріпочуть.
В когось щастя в грошах,
Хтось мільярди складає,
А хтось все віддає
До краплинки, до краю...
Біль війна принесла
Та навчила любити...
Не втомився! Не час!
Моїм дітям тут жити!

Приспів. (2)

Наче два різні світи,
Я не втомився, а ти?..','[''pisni.org.ua'', ''cat:ato'', ''cat:devoted'', ''Пісні російсько-української війни та АТО'', ''Пісні присвячені окремим особам'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4338434'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4338434','Я не втомився','Я не спав шість ночей,
Руки стерпли від болю,
А в думках лиш на мить
Вириваюсь на волю...
Я забув про брехню,
Про чиюсь бездіяльність,
Знову град прилетів,
Повернув у реальність...
Третю зиму вогню
Нам війна гарантує,
На своєму шляху
Все безжально руйнує...
А я мовчки роблю
Те, що маю робити,
Бо це наша земля!
Моїм дітям тут жити!

Приспів:
Я не втомився! Сили я маю!      |
Я ворогів у твій дім не пускаю! |
Наче два різні світи,           |
Я не втомився, а ти?..          | (2)

Я не спав шість ночей,
А думки полетіли
До дітей, що для нас
Обереги зробили,
До жінок, що в молитві
Проплакали очі,
І за стукіт сердець,
