INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4338532','Тая-Тай','Музика: Олег Винник Слова: Олег Винник. Виконує: Олег Винник','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Очима я обіймаю
Та холод твій я ковтаю,
Замерзаю...
Ти серце моє розіп''яла
Та глибоко в душу запала
І не знала: без тебе йду,
Спотикаюсь, воюю з собою,
Змагаюсь, сподіваюсь...
Вдихаю чи видихаю,
Не бачиш, як я кохаю,
Я кохаю...

Приспів:
Таю, Таю, Тай,
Мені дай, дай, дай
Свого тепла!
Таю, Таю, Тай,
Ти най-най-най,
Така одна!

Тобі буду вічним літом
І золотом, і самоцвітом,
Цілим світом...
В намисто дні намизала,
Чим ти мене прив''язала -
Не сказала...
Не кликала і не гукала,
Ходила не помічала,
Обминала...
Усе б на місця свої стало,
Якби ти мене покохала,
Покохала...

Приспів. (2)','[''pisni.org.ua'', ''cat:nostalgia'', ''Пісні з ностальгічними мотивами'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4338532'), datetime('now')),datetime('now'));
