INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_433838','А в Печі Пироги печуцця','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Співаймо Світові-Дитині © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004 2. Щедрий вечір. Українські народні пісні. Пісенник. Упорядкування та передмова Н. Д. Якименко. - К.: Музична Україна, 1989. - 192 с.','Порівняти до Загадок про сало-дитинку ("серед Хати Сало висить" - дитина в колисці), та до Колядок про Місяць-дитинку. Стародавні Колядки-Щедрівки: Українські Різдво Світа і Щедрий Вечір. Радуйся Земле Коляда їде! Листки з приводу цієї Пісні: Що означає ім''я "Коляда"? Що означає "Дідух"? Співаймо Світові-Дитині: Колядки, Щедрівки, Колискові... Стежки до листків про Українські традиції.','А в Печі Пироги печуцця
А Дітям їсти не даюцця
Один доти заглядав
Поки таки не достав тай із''їв

А в Печі Пирогів не стало
Він поліз на Гору по Сало
Того Сала не дістав
Послизнувся тай упав ой упав!

Ой вийшов Хазяїн із Хати
Тай став його дручком обертати
Чекай-чекай Панотче
Не полізу поночі на цей раз','[''pisni.org.ua'', ''cat:dytyachi'', ''cat:kolyadky'', ''cat:shchedrivky'', ''cat:zhartivlyvi'', ''Дитячі пісні'', ''Колядки'', ''Щедрівки'', ''Жартівливі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_433838'), datetime('now')),datetime('now'));
