INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_429632','Ой на Горі на Могилі','Українська народна пісня. Виконує: Микола Будник','uk','ukraine_before_1917',NULL,NULL,'Співає зі старосвітською бандурою кобзар Микола Будник: Воскресні та Спасительні пісні © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2003','* варіант: Ой у полі на Могилі Спасительна: світ не по Правді. Українські релігійні роздуми про Воскресіння, Неволю і Спасіння. Ой Ми зіслані на признаванє. Нема в світі Правди не зіскати. Ой устань же Козаченьку. Козака несуть і Коня ведуть Ой летів Пугач тай через Могилу Ой Морозе Морозенку ти Славний Козаче Ой на Горі на Могилі Ой піду я Лугом Лугом-Долиною Ой сів Пугач на Могилі Там за Лісом за Лугом ходить Козак за Плугом Козак від''їжджає Дівчинонька плаче. Байді Молодому Мед-горілку пити. Но ми докажем своїм Клинком. Ворогів як ту худобу Виганяй із Краю. Листки з приводу цієї Пісні: Коляда і Великдень: Різдво і Відродження Світа. Гаїлковий Білоданчик і Первісний Молодець-Стрілець Українські реліґійні роздуми про Неволю та Спасіння Еротичні містерії, тиждень від Катерини 7.12 до Калети. Доля. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Стежки до листків про Українські традиції.','Ой на Горі на Могилі*
Гей на Горі на Могилі

На Широкій Україні
Гей на Широкій Україні

Лежить Козак там Убитий
Гей лежить Козак там Убитий

На Купину головою
Гей на Купину головою

Прикрив очі Муравою
Гей прикрив очі Муравою

А рученьки Китайкою
Гей а рученьки Китайкою

А ніженьки Нагайкою
Гей а ніженьки Нагайкою

Ой устань же Козаченьку
Гей  ой устань же Молоденький

Нагаєчку возьми в руки
Гей Нагаєчку возьми у руки

Ворогів як ту худобу
Виганяй із Краю','[''pisni.org.ua'', ''cat:dumy'', ''cat:kozacki'', ''Думи'', ''Козацькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_429632'), datetime('now')),datetime('now'));
