INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4293532','Коли в житті незгоди','Українська народна пісня. Виконує: Берники','uk','ukraine_before_1917',NULL,NULL,'http://www.e-christian.info/sites/default/files/sbormik_2011_v1.0.pdf',NULL,'Gm
Коли в житті незгоди,
Cm
Чи радісне життя,
Чи вдома чи в дорозі
Співаю пісню я.
Вона іде зі мною
Ця пісня неземна.
Маленькі з нею гори,
І ями - рівнина.
Мелодія любові
І пісня про Христа
Ведуть мене до неба
В щасливе майбуття.
Закінчиться надія
І віра теж пройде,
Мелодія любові
Ніколи не мине.
Мелодія любові
І в небі не мине.','[''pisni.org.ua'', ''cat:christian'', ''Пісні на християнську тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4293532'), datetime('now')),datetime('now'));
