INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4340787','Сонечко','Музика: Алла Мігай Слова: Леонід Ямковий','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Прокидаються звірята,
Зацвірінькали пташки,
Ніжні квіти у Карпатах
Розкривають пелюстки.
Гей, виходьте, діти, з хати
Та збирайте весь народ:
І дорослі, і малята
Починаєм хоровод!

Приспів:
Де ти, ясне сонечко?  |
Де? Де? Де?           |
Принеси нам, сонечко, |
День, день, день!     |
Прожени нам, сонечко, |
Тінь, тінь, тінь!     |
Усміхнися, сонечко,   |
Дінь, дінь, дінь!     | (2)

Сонце сяє у Карпатах
Небувалої краси,
У свої святкові шати
Повдягалися ліси,
Танок сонця знову лине -
Всі у нім: старі й маля!
Ось яка у нас країна,
Ось яка у нас земля!

Приспів.

Дінь! Дінь! Дінь!','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''Пісні про красу природи'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4340787'), datetime('now')),datetime('now'));
