INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4340930','Ніжна колисанка','Музика: Олег Петров Слова: Марія Морозенко','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'В сну рожеві хвилі
Заколишуть вечір,
Засріблиться місяць
Над гніздом лелечим.
Солодко й спокійно
Дітки спочивають,
Ніжну колисанку
Зорі їм співають.

Приспів:
Слухай ніжну колисанку
І спи солодко до ранку...
Сплять у нірочках звірята,
У гніздечках - пташенята.
Оченята закривай,
Люлі-люлі, засинай,
Люлі-люлі, засинай...

Пропливає казка
В човнику срібненькім,
Доторкнеться ласка
Діточок маленьких.
Спи, дитя кирпате,
Спи, маленька втіхо,
Хай в житті твоєму
Вік не буде лиха.

Приспів. (2)

Люлі-люлі, засинай','[''pisni.org.ua'', ''cat:kolyskovi'', ''Колискові'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4340930'), datetime('now')),datetime('now'));
