INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_433889','Колядую колядую Ковбасу чую','Українська народна пісня. Виконує: Тріо Либідь, Олександр Гаркавий','uk','ukraine_before_1917',NULL,NULL,'Співаймо Світові-Дитині © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Стародавні Колядки-Щедрівки: Українські Різдво Світа і Щедрий Вечір. Радуйся Земле Коляда їде! Читати листки з приводу цієї Пісні: Що означає ім''я "Коляда"? Що означає "Дідух"? Співаймо Світові-Дитині: Колядки, Щедрівки, Колискові... Стежки до інших листків про Українські традиції.','Колядую колядую Ковбасу чую
Де Ковбасу чую там і заночую
Приспів:
Щедрий Вечір Добрий Вечір
Добрим Людям на Здоров''я!

А в нашого Дядька та Дядина Гладка
Ой не хоче встати Ковбаси дати
А Дядина Гладка бо таку Бог дав
Не клади край Вікна щоб ніхто не вкрав
Ковбаса хороша дайте ще і гроші
Ковбаса та гроші то й Різдво хороше
Колядую-колядую','[''pisni.org.ua'', ''cat:kolyadky'', ''cat:shchedrivky'', ''Колядки'', ''Щедрівки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_433889'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_433889','Колядую колядую Ковбасу чую','Колядую колядую Ковбасу чую
