INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_430430','Ой з-за гори вітер віє','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1958','Шевченків край: Історико-культурологічні нариси. - К., 2005. С. 453.','Записали Л. Ященко та Л. Орел від гурту дівчат у с. Павлівщина Драбівського району Черкаської області 1958 року. Пісня з добірки Леопольда Ященка.','Ой з-за гори вітер віє,
З-за гори,
Та й нема мого миленького
З дороги.

Ой чи приїхав мій миленький,
Чи прийшов,
Та стихесенька під віконце
Підійшов.

Ой здорова, моя мила,
Чи чуєш?
Ой з ким же ти, моя мила,
Ночуєш?

Ой не сама, мій миленький,
Не сама,
Та з своїми діточками
Обома.

Та одно кладу від краю,
Друге від стіни,
Та сама ляжу, молодая,
Між ними.

Та сама ляжу, молодая,
Між ними,
Та й умиюся слізоньками
Дрібними.

Та й умиюся слізоньками
Дрібними,
Та й утруся рукавами
Шитими.','[''pisni.org.ua'', ''cat:kupalski'', ''Купальські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_430430'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_430430','Ой з-за гори вітер віє','Ой з-за гори вітер віє,
З-за гори,
