INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_434535','Ми не самі йдем ми Козу ведем','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Де Коза ходить, там Жито родить! © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Українська Святочна установа Колядників походить з далеко старших часів, чим Римські та інші маскаради, які всі суть орієнтовані на культ Сонця і належать до пізнішого, вторинного, культурно-історичного округа. Українські ходження з Козою є зовсім іншого типу — і в них "Берези" нема. Вони належать передовсім до обрядів Новорічних і Щедровечірніх та лиш через перемішання з Різдвяними увійшли в Різдвяний час і мають свою власну мітольоґійну орієнтацію й характеристику. Де Коза ходить там Жито родить! Читати листки з приводу цієї Пісні: Щедрий Вечер, 13-14 січня: Миланки-Васильки. Щедрий Вечер, 18-19 січня: Святі Водорщі. Стежки до інших листків про Українські традиції.','Ми не самі йдем ми Козу ведем!
Ми Козу ведем з Козенятами
На Горі Вовчок з Вовченятами
Де взявся Вовчок за Козу чок-чок
А Вовченята за Козенята
Ой Ти Козо ой Ти Білая
Ти пішла б в Лісок щоб нажать Снопок
Ой Сінця Снопок для Малиx Діток
Ой не йди не йди побачать Люди
Бо в тому Лісі всі Люди-Стрільці
Поxовалися розxовалися
Xочуть Козу вбить Шкуру облупить
М''ясо порубать Собакам віддать
А я тиx Стрільців тай не боюся
Тілько боюся Старого Діда
Що в того Діда Сива Борода
Ой над головою Дід із Булавою','[''pisni.org.ua'', ''cat:shchedrivky'', ''Щедрівки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_434535'), datetime('now')),datetime('now'));
