INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4345030','Добрий день, вкраїнська школо!','Музика: Віталій Лазаренко Слова: Василь Дерій','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Добрий день,
Вкраїнська школо!
Зустрічай нас,
Перший класе!
Ми влились
В учнівське коло,
Щоб іти у ногу
З часом!

Приспів:
Добрий день!
Добрий день!
Добрий день!
Нашій школі,
Нашій долі
Добрий день!

А коли нам важко буде —
Дай нам сили, Божа Мати,
Першій вчительці терпіння
Знань та мудрості навчати!

Приспів. (2)','[''pisni.org.ua'', ''cat:shkilni'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4345030'), datetime('now')),datetime('now'));
