INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4348134','Десь по світу','Музика: Луїс Фонсі Слова: Роман Стахнів','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконують Вероніка Мацигін, Анна-Марія Іваночко, Марта Михаць, Оля Герман, Валентин Яворський, Анна Кубів, Оля Тимишин, Остап Староста, Анастасія Юрчак﻿.','Дивись, який реально красивий
Наш з тобою край:
Голи, доли, ріки, чорнозем!
Дивись, які реально мудрі люди
Народились в нас:
Франко, Стефаник, Шульц і Котермак.
Ми можемо зробити все самі,
Можем обійти ми пів Землі,
Але навіщо нам іти?..
Я візьму все в свої руки і піду,
І допоможу всім, хто зазнав біду,
Я почну міняти світ із себе!

Приспів:
Десь по світу
Ти шукаєш іншу Україну,
А вона живе в твоєму серці
Незалежна вільна і єдина,
Рідна Україна!
Десь по світу
Майбуття ти сам собі будуєш,
В пошуках багатства і добра
Мандруєш...
Повертайся на Вкраїну будувати
Справжню Батьківщину!

Українські пісні і танці
Тільки твого серця ритму
Мова наша солов''їна
Милозвучна, як молитва.
Є відомі в світі наші
Науковці і спортсмени,
Мудреці і музиканти,
А які у нас поети:
Ліна Костенко і Тарас Шевченко,
Сосюра, Франко і Леся Українка
Писали всі для нас,
А ви живете там,
Там співаєте чужі пісні
І стукаєте в там-там.
А наші цимбали, скрипка і трембіта
Так файно звучали, за душу чіпали.
Наші Верховинці, Бойки і Гуцули,
Лемки і Мазури по горах танцювали.

По світу по світу нас порозкидало,
Нас тепер чимало по цілому світу
І все на світі треба пережити,
І наперед не треба ворожити!..
По світу по світу нас порозкидало,
Нас тепер чимало по цілому світу,
І кожен фініш це по суті старт,
І за минулим плакати не варт...

Приспів.

Українські пісні і танці
Тільки твого серця ритму
Мова наша солов''їна
Милозвучна, як молитва.
Є відомі в світі наші
Науковці і спортсмени,
Мудреці і музиканти,
А які у нас поети!
По світу по світу нас порозкидало,
Нас тепер чимало по цілому світу,
Повертайся будувати
Справжню Батьківщину, рідну Україну!
По світу по світу нас порозкидало,
Нас тепер чимало по цілому світу,
Повертайся будувати
Справжню Батьківщину, рідну Україну!    Фонограма-мінус (mp3, 320 kbps). Luis Fonsi ft. Daddy Yankee - Despacito','[''pisni.org.ua'', ''cat:patriotic'', ''Патріотичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4348134'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4348134','Десь по світу','Дивись, який реально красивий
Наш з тобою край:
Голи, доли, ріки, чорнозем!
Дивись, які реально мудрі люди
Народились в нас:
Франко, Стефаник, Шульц і Котермак.
Ми можемо зробити все самі,
Можем обійти ми пів Землі,
Але навіщо нам іти?..
Я візьму все в свої руки і піду,
І допоможу всім, хто зазнав біду,
Я почну міняти світ із себе!

Приспів:
Десь по світу
Ти шукаєш іншу Україну,
А вона живе в твоєму серці
Незалежна вільна і єдина,
Рідна Україна!
Десь по світу
Майбуття ти сам собі будуєш,
В пошуках багатства і добра
Мандруєш...
Повертайся на Вкраїну будувати
Справжню Батьківщину!

Українські пісні і танці
Тільки твого серця ритму
Мова наша солов''їна
Милозвучна, як молитва.
Є відомі в світі наші
Науковці і спортсмени,
Мудреці і музиканти,
А які у нас поети:
Ліна Костенко і Тарас Шевченко,
Сосюра, Франко і Леся Українка
Писали всі для нас,
А ви живете там,
Там співаєте чужі пісні
І стукаєте в там-там.
А наші цимбали, скрипка і трембіта
Так файно звучали, за душу чіпали.
Наші Верховинці, Бойки і Гуцули,
Лемки і Мазури по горах танцювали.

По світу по світу нас порозкидало,
Нас тепер чимало по цілому світу
І все на світі треба пережити,
І наперед не треба ворожити!..
По світу по світу нас порозкидало,
Нас тепер чимало по цілому світу,
І кожен фініш це по суті старт,
І за минулим плакати не варт...

Приспів.

Українські пісні і танці
Тільки твого серця ритму
Мова наша солов''їна
Милозвучна, як молитва.
Є відомі в світі наші
Науковці і спортсмени,
Мудреці і музиканти,
А які у нас поети!
По світу по світу нас порозкидало,
Нас тепер чимало по цілому світу,
Повертайся будувати
Справжню Батьківщину, рідну Україну!
По світу по світу нас порозкидало,
Нас тепер чимало по цілому світу,
Повертайся будувати
Справжню Батьківщину, рідну Україну!    Фонограма-мінус (mp3, 320 kbps). Luis Fonsi ft. Daddy Yankee - Despacito');
