INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_434137','Ой учора а звечора пасла Маланка бай Качура','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Співаймо Світові-Дитині © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Пасла Маланка Два Качура Шовки пряла Шидри ткала. Символіка Щедрого Вечера і Василя. Щедрий Вечер, 13-14 січня, зачинається властиво під Новий Рік (7 днів наперед Богоявління — символ Місячний!), т. є. в вечер перед св. Василя. Це особливо улюблене Українське свято: мітичного Василя і Маланки, — є найщирішим шануванням Місяця з його женихальними мотивами (ними переповнені Щедрівки). Тоді мітичну постать Василя мішають часто з мітольоґійно-Місячною постаттю Іллї — Ілії, який є в Українського народу покровителем урожаїв збіжжя, особливо жита (сніп жита, дід Ілля, — в часі жнив, — це постава Місяця). Стежки до інших листків про Українські традиції.','Ой учора а звечора
Пасла Маланка бай Качура | (2)

Ой пасучи загубила
Тай шукаючи заблудила    | (2)

Заблудила в Чистім Полі
Аж там Її Василь оре     | (2)

Ані оре ані плуже
За Маланочков барзенько туже   | (2)

Іде Васильчик а з корчми п''яний
Втвори Маланко я Твій коханий  | (2)

Васильчику бай Чирчику
Посійю ж Тебе в Городчику | (2)

Буду ж Тебе шанувати
Сім раз на день поливати  | (2)

Сім раз на день поливати
В Неділю рано обривати    | (2)

В Неділю рано обривати
Тай Маланочку обтикати    | (2)

Ой мала Нічка-Петрівочка
Не виспалася Маланочка    | (2)

Шовки пряла Шервети ткала
Тай до Милого посилала    | (2)

Шовки пряла Шидри ткала
Тай до Милого посилала    | (2)

Не мої Шовки не мої Шидри
Лиш Моя Мила Маланочка    | (2)','[''pisni.org.ua'', ''cat:shchedrivky'', ''Щедрівки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_434137'), datetime('now')),datetime('now'));
