INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4349735','Ведмедик Клишоногий',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ранком ведмежатко через ліс іде,
