INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_43430','Божий Син днесь народився','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,'Записано у Закарпатті Іршавський район','Божий Син днесь народився
Свише ко нам понизився,
Із Діви нетлінни,
Із Пренепорочни Воплотився.

Породила Бога Слово
Од кореня Давидова
Божая Невіста,
Марія Пречиста Йакимова.

Возвістив бо ангельський глас
Пришествіє Його до нас,
Що Його рождества із человічества
Уж прийшов час.

Соєдинив Він нетлінно
Два существа нероздільно
Во єдиной особі,
А двойной природі непреложно.

Нашим тілом облечеся,
А Ісусом наречеся.
Так бо то уж давно
Пророками явно, предречеся.

Приход Єго в конець віков
Подаровав для язиков
Благословеніє
І упознаніє, Отця світов.

Земля вертеп укращає,
Небо звізду посилає
Указати місто
Де Месія исто, возлягає.

Пастиріє усі грають,
Хвалу Богу воздавають,
Рожденна первенця,
Дівича младенця, привітають.

Видять єго ряндинами
Покритого, а сукнами
Нищетно одита,
Во яслах повита пеленами.

Ідуть царі із далека,
Несуть дари для отрока:
Злато, ливан, смирну
Спасителю мирну од Востока.

Звіздословці во храмині
Поклоняються дитині,
Рожденной без отця,
Бувшу прежде сонця, по істині.

Прийшов він світ просвітити
А грішників окупити
Од ада ужасна,
Упадка нещасна, свободити.

Зато Христа прославляє
Всяка твар і величає.
Перед ним коліна
Кажда душа вірна, преклоняє.

Царським словом записане
В Вифлеємі, Божий Сине,
Спаси всі племена,
їм же суть імена: земляне.

Живущий Ти во вищності,
Сохрани нас од напасті,
Од войни і глада
І темного ада. Во вічності.','[''pisni.org.ua'', ''cat:christian'', ''cat:kolyadky'', ''cat:narodni'', ''cat:zakarpatski'', ''Пісні на християнську тематику'', ''Колядки'', ''Народні пісні'', ''Закарпатські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_43430'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_43430','Божий Син днесь народився','Божий Син днесь народився
Свише ко нам понизився,
Із Діви нетлінни,
Із Пренепорочни Воплотився.

Породила Бога Слово
Од кореня Давидова
Божая Невіста,
Марія Пречиста Йакимова.

Возвістив бо ангельський глас
Пришествіє Його до нас,
Що Його рождества із человічества
Уж прийшов час.

Соєдинив Він нетлінно
Два существа нероздільно
Во єдиной особі,
А двойной природі непреложно.

Нашим тілом облечеся,
А Ісусом наречеся.
Так бо то уж давно
Пророками явно, предречеся.

Приход Єго в конець віков
Подаровав для язиков
Благословеніє
І упознаніє, Отця світов.

Земля вертеп укращає,
Небо звізду посилає
Указати місто
Де Месія исто, возлягає.

Пастиріє усі грають,
Хвалу Богу воздавають,
Рожденна первенця,
Дівича младенця, привітають.

Видять єго ряндинами
Покритого, а сукнами
Нищетно одита,
Во яслах повита пеленами.

Ідуть царі із далека,
Несуть дари для отрока:
Злато, ливан, смирну
Спасителю мирну од Востока.

Звіздословці во храмині
Поклоняються дитині,
Рожденной без отця,
Бувшу прежде сонця, по істині.

Прийшов він світ просвітити
А грішників окупити
Од ада ужасна,
Упадка нещасна, свободити.

Зато Христа прославляє
Всяка твар і величає.
Перед ним коліна
Кажда душа вірна, преклоняє.

Царським словом записане
В Вифлеємі, Божий Сине,
Спаси всі племена,
їм же суть імена: земляне.

Живущий Ти во вищності,
Сохрани нас од напасті,
Од войни і глада
І темного ада. Во вічності.');
