INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4350389','Многая Літа Священику!','Слова: Хор села Винятинці','uk','ukraine_1991',NULL,NULL,NULL,'Пісню виконує хор села Винятинці.','За несім молитву творю всього світа,
Заспіваймо отцю: Многая Літа!
Многая, многая літа!
Многая, многая літа!
Многая літа! Хай сонце світить
І Бог здоров''я щастя вам дає!

Нехай вам Всевишній в труді помагає,
І здоров''я ласки з неба посилає!
Многая, многая літа!
Многая, многая літа!
Многая літа! Хай сонце світить
І Бог здоров''я щастя вам дає!

Дякуєм вам, Отче, за щиру Молитву,
