INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_429333','Ой зза Гори зза Лиману Вітер повіває','Українська народна пісня. Виконує: І. Рачок','uk','ukraine_1991',NULL,'2001','1. Співає зі старосвітською бандурою кобзар Микола Будник: Воскресні та Спасительні пісні © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2003. 2. Українські релігійні роздуми про Спасіння © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2003.','Звукове джерело: Берви. Український традицiйний фольклор. Кружало. Проект "Моя Україна". 2001. Плач України. Дума про руйнування Січі. Спасительна: світ не по Правді. Українські релігійні роздуми про Воскресіння, Неволю і Спасіння. Ой Ми зіслані на признаванє. Нема в світі Правди не зіскати. Господа Милосердного прохали та благали. Кругом Січі Запорізької москаль облягає. Заплакала Україна така її Доля. Листки з приводу цієї Пісні: Українські реліґійні роздуми про Неволю та Спасіння Еротичні містерії, тиждень від Катерини 7.12 до Калети. Доля. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Стежки до листків про Українські традиції.','Ой зза Гори зза Лиману Вітер повіває
Кругом Січі Запорізької москаль облягає
Облягає москаль Січу табором стали
Вони свого генерала три дні ожидали
Метнулися по куренях запасу шукати
А московська вся старшина церкви оббирати
Тай беруть срібло беруть злото ще й воскові свічі
Зостаєцця Пан Кошовий з Писарьом в Січі

Ой встань Петре ой встань Батьку просять же нас люди
Як станемо на гряниці по прежньому буде
Як станемо на гряниці та впросим царицю
Щоб віддала степи вільні по прежню гряницю

Не на те ж я вражий син москаля зібрала
Щоб Степ Добрий Край Веселий назад повертала

Ой встань Петре ой встань Батьку що ж ми наробили
Що Степ Добрий Край Веселий тай занапастили

Одна хмара зза Лиману а другая з Поля
Заплакала Україна така її Доля
Тай заплакала Україна така її Доля

ВІДМІНА:

Ой з-за Гори з-за Лимана Вітер повіває
Кругом Січі запорозькій москаль облягає.
Облягає Москаль Січі таборами стали,
Вони свого генерала три дні дожидали.
Шатнулися по курінях запасу шукати,
А московська вся старшина церкви обдирати.
Та беруть срібло, беруть злото, ще й воскові свічі,
Зостається пан кошовий з писарями в Січі.
Ой устань Харку, устань батьку, просять же нас люде,
Як станемо на границі, по прежньому буде.
Як вийдемо на границю, та впросим царицю,
Щоб оддала степи вольні по третю границю.
Та не на те-ж, вражі сини, москаля зібрала,
Щоб степ добрий, край веселий назад завертала.
Ой устань Харку, устань батьку, що-ж ми наробили,
Що степ добрий, край веселий тай занапастили!
Та тече річка невеличка зпід білої кручі,
Заплакали Запорожці від цариці йдучи.
Встає хмара з-за лиману, а другая з поля,
Заплакала Україна, така її доля','[''pisni.org.ua'', ''cat:dumy'', ''cat:istorychni'', ''cat:kozacki'', ''cat:suspilno-politychni'', ''Думи'', ''Історичні пісні'', ''Козацькі пісні'', ''Суспільно-політичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_429333'), datetime('now')),datetime('now'));
