INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_435034','Там в Виноградку в Зеленім Садку','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Зелена Яблунь Червоне Ябко зродила... Я вам не вирву Милому стежу — Не вирве, бо стежить Милому? Не вирве нікому Яблучко, бо то стежка для Милого? Тим більше, що воно однЕ, Одне? Я Тобі зірву я Тобі стрясу — Хто каже? Стародавні Колядки-Щедрівки: Українські Різдво Світа і Щедрий Вечір. Десь узялася Молода Дівчина. Питання походження людини в Колядкових переказах. Одною з найцікавіших загадок Колядкової космоґонії є походження людини. Про її сотворення нема виразної споминки в Колядках. (Приміром, зачинаючи про Райське Дерево, Святочні пісні далі співають: "Десь узялися Райськії Пташки... — Десь узялася Молода Дівчина"! Лишається подивуватися. Пісні так зважено і обережно говорять про сучасну наукову проблему походження життя на Землі: "Десь узялося!..":-) Нема в них і сліду подібного бачення, як в історії біблійній про Сотворення окремо тіла і душі чоловіка; або хоч би загального переказу про Сотворення людей вищим духовим Єством, як це оповідає багато світотворчих переказів світа. У переказах Уралалтайських та Австронезьких, зближених до Колядкових переказів про перших людей, сказано виразно про зродження людей з першого дерева на світі. Але в Колядках нігде про це не говориться, хоч Світотворчі Колядки співають про появу перших людей в подобі Астральних Світил на Райськім Дереві, або у містичних Небесних святинях (з Райського Дерева). Прадерево, Місяць і Астральна Трійця. Зрозуміння цеї загадки мусимо, послідовно, шукати серед реліґійних та мітольоґійних образів Свята Різдва Світа (й Щедрого Вечера) та Колядок і Щедрівок. І розв''язка її дійсно там є, тільки не в пракультурнім реліґійнім світогляді народу, а в Місячно-мітольоґійнім, хоч все-таки в дуже первіснім його вислові. Колядкові перекази про походження людини є алеґорійні, убрані в Місячну символіку і є висловом Місячної мітольоґії, яка в образцях зродження людини має своє з''ображення. Українська Місячна мітольоґія є оцим особливою, що не все відноситься до Місяця як Астральної одиниці, але також до його кружень і перемін в часі чотирьох його астрономійних фаз (відмін). Вона бере на увагу його зродження, зріст і розвиток, повну появу на Небі і загибіль. І так появу Місяця як цілости, як рівнож його появу в астрономійних фазах, лучать Колядки й Щедрівки з Райським Деревом. Тому, що Райське Дерево, або Прадерево, є перворядним Місячним мотивом у світовій і Колядковій мітольоґії, стала поява Першої людини на землі й поява Місяця на світі зв''язаною з Прадеревом; відтак стали ці обі появи тотожними; а в розширенні образів стали тотожними — Українська Астральна Трійця та Перша Рідня. І всі ті мітольоґійні образці лучить Український нарід з Прадеревом. З цих мітольоґійних поєднаних образів витворився погляд, що Перші люди зродилися на Прадереві. (Те, що Святочні пісні пов''язують появу людей з Райським Деревом, — символ зоряного неба, — відповідає сучасними науковими теоріями космічного походження життя.) Не мають ніякого зв''язку з таким світоглядом перекази народів Сходу й Полудня про залежність життя перших людей, або походження їх, від прадерева. Історія біблійна про дерево життя ставить його як мірку вартости життя людського, залежної від душевної стійности чоловіка, від його вибору добра або зла, життя або смерти; Сотворення ж чоловіка приписує Найвищому Єствові. Інші перекази оповідають про зродження людини прямо з дерева. Міт Індоіранський розказує про походження людей з андроґенної, — чоловічо-жіночої, — ростини, двох деревин-близнят, ростучих з одного кореня й сплетених з собою, які відтак прийняли людську подобу. Подібний переказ Мендулянських Каянів з острова Борнео оповідає про перше дерево бамбусове й ростину ротанґ, що доокола нього обвилася, від чого воно виросло до небувалої величини. На нього впало два духи з неба, — чоловік і жінка, — і вони з речовини з того дерева сотворили перших людей. (Бамбусове – бамбукове, bambu (мал.), результат видозміни mambu (мал.).) В Уралалтайськім переказі сказано, що в почині світа росло одиноке дерево без конарів. Воно не подобалося Богові в такім виді і він сказав: нехай буде на дереві дев''ять конарів, а при їх насадах нехай буде дев''ять людей, а з цих людей нехай буде дев''ять племен. Після іншого Уралалтайського переказу син божий Нумі Торум сотворив людей з верболозу і глини. (Конар — велика гілка дерева.) З цих переказів не видно ніяких запозичень ані навіть далеких подіб у світобаченні Колядок про Перших людей. Є деякі зближення образів, але їх належало би лучити радше зі світобаченням племен глибокого Полудня, аніж народів Уралалтайських або Індоіранських. (За працею: о. Ксенофонт Сосенко. "Культурно-історична постать Староукраїнськиx свят Різдва і Щедрого Вечора". Львів, 1928. - СІНТО, Київ 1994. 343с.) Читати листки з приводу цієї Пісні: Колядки як Українські релігійні роздуми про Бога. Стежки до інших листків про Українські традиції.','Там в Виноградку в Зеленім Садку

Приспів:
Зелена Зелена Яблунь
Червоне Ябко Зродила.

Там Марусенька Яблук стерегла
Прийшов до Неї Батенько Її
Маруню Дочко вирви Яблучко
Я Вам не вирву Милому стежу

Там в Виноградку в Зеленім Садку
Там Марусенька Яблук стерегла
Прийшла до Неї Матінка Її
Маруню Дочко вирви Яблучко
Я Вам не вирву Милому стежу

Там в Виноградку в Зеленім Садку
Там Марусенька Яблук стерегла

Прийшов до Неї Миленький Її
Я Тобі зірву я Тобі стрясу

