INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4353434','Богуслав понад Россю','Музика: Тарас Силенко Слова: Микола Щербак. Виконує: Тарас Компаніченко, Володимир Самайда, Тарас Силенко, Валерій Мартишко','uk','ukraine_1991',NULL,'2017','Літопис авторської пісні України №52 (484) 2017 рік.',NULL,'Богуслав понад Россю
І Корсунь в боях стугонять.
Біла Церква гримить -
Москалів блискавицями стріла.
Наш отаман як грім:
У Черкасах сідлає коня,
Над Дніпром пролетить,
У Таращі розпростує крила...

Як вогонь він випалює
Й нищить московську орду,
Мов двосічним мечем
Розбиває червоних бандитів!
У Трипіллі Зелений
Подивиться в мряку густу,
Де в огні клекотить
І вирує розтерзаний Київ...

Заскрегоче зубами, гляне
З болем на рідне село,
Стисне в боки коня і,
Як вихор, шугне в надвечір''я...
Вільна Січ ожила,
І козацтво, як мак, розцвіло, -
Це Зелений у вічність
Веде українське безмір''я!','[''pisni.org.ua'', ''cat:istorychni'', ''Історичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4353434'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4353434','Богуслав понад Россю','Богуслав понад Россю
