INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_435333','Ой в Саду Саду Пава ходила','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Співаймо Світові-Дитині © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Десь узялася Молода Дівчина. Листки з приводу цієї Пісні: Колядки як Українські релігійні роздуми про Бога. Ой стояла Липка Тонка та Висока Рокове Коло. Стежки до листків про Українські традиції. Староукраїнські Колядки і Щедрівки: Святе Різдво (Свято Різдва Світа: Свят-Вечір – Коляда)... Щедрий Вечір (Свято Місяця й Прадіда: Новий Рік ― Святі Водорщі) ― Весілля: Дівич-Вечір... Великдень... Зелені Свята (Трійця) ― Царинні Містерії... Івана Купала... Астральні Жнива... Рокове Коло.','Ой в Саду Саду Пава ходила
Пава ходила Пір''я губила

Ой а за нею Красна Панна
Пір''я збирала в Фартушок клала

В Фартушок клала Віночки плела
Звивши Віночок пішла в Таночок

З Таночка прийшла по Воду пішла
Ой пішла вона Крайом-Дунайом

Крайом-Дунайом понад Бережком
Десь та взялися Буйнії Вітри

Ой війнули Вінок скинули
Вінок скинули в Дунай кинули

Десь узялося Три Риболовці
Три Риболовці Всі-три-молодці

Ой закиньте ж ви Шовковий Невуд
Витягніте мені мій Новий Вінець

Мій Новий Вінець Золот Перстенець
То я вам оддам Три Нагороди

Три Нагороди Всі-три-в-городі
Одному буде мій Новий Вінець

Другому буде Золот Перстенець
Третьому буду Сама Молода

Третьому буду Сама Молода
Сама Молода-так-як-ягода','[''pisni.org.ua'', ''cat:shchedrivky'', ''Щедрівки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_435333'), datetime('now')),datetime('now'));
