INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_43539','На небі зірка ясна засяла','Українська народна пісня. Виконує: Інеса Братущик, Орест Хома','uk','ukraine_before_1917',NULL,NULL,'народна коляда',NULL,'На небі зірка ясна засяла
І ясним світлом сіяє,
Хвиля спасення нам завітала, -
Се бо Христос ся рождає.

Щоб землю з небом в одно злучити,
Христос родився, славіте!     | (2)

В біднім вертепі, в яслах, на сіні,
Спочив Владика, Цар світу.
Ото ж, до Нього спішім всі нині, -
нашого жде Він привіту.

Спішім любов''ю його огріти,
Христос родився, славіте!     | (2)

Благослови нас, Дитятко Боже,
Даруй нас нині любовю,
Хай і пекельна сила не зможе
Нас розділити з Тобою.

Благослови нас, ми ж Твої діти,
Христос родився, славіте!     | (2)

Благослови нас, наш любий Христе,
Зло побідити силу дай,
Засій в серцях нам бажання чисте -
Міцно любити рідний край:

Щоб Україна могла радіти,
Христос родився, славіте!     | (2)','[''pisni.org.ua'', ''cat:christian'', ''cat:kolyadky'', ''cat:narodni'', ''cat:zakarpatski'', ''Пісні на християнську тематику'', ''Колядки'', ''Народні пісні'', ''Закарпатські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_43539'), datetime('now')),datetime('now'));
