INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4352838','Батьки мої','Музика: Оксана Корзун-Омеляш Слова: Оксана Корзун-Омеляш. Виконує: Оксана Корзун-Омеляш','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Заповітна мрія батьків,
Аби діти жили в любові,
Щоб у кожного у житті
Була тільки щаслива доля!
Щоб сестра любила сестру
Так, як Бог заповів любити,
Щоб у мирі жили брати,
Бо направду так треба жити!

Приспів:
Батьки мої, мої батьки,
Куди ж той час біжить куди?
Я Господа за Вас молю,
Він знає як я Вас люблю!
Нехай біжить собі той час,
Я Богу дякую за Вас
І прошу для усіх батьків
Здоров''я і щасливих днів!

Хоч і різне буває в житті
Та змінити ніхто не в змозі
Моїх до Вас почуттів,
Завжди серцем на Вашім порозі.
Ми цінуєм, коли залишаєм
Та без тої гіркої розлуки,
Ми ж і вдячності не пізнаєм
І любові нам не збагнути...

Приспів.','[''pisni.org.ua'', ''cat:pro-batkiv'', ''Пісні про любов до батьків'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4352838'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4352838','Батьки мої','Заповітна мрія батьків,
