INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4351430','Моє море','Музика: Тимур Усманов, Тетяна Сава Слова: Тетяна Сава, Артур Заблацкас. Виконує: Віталій Козловський','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Я сумую кожен раз,
Коли втрачаю тебе...
На хвилину
Забираєш всі слова,
Слухаєш, мовчиш... -
Але чия провина...
Всі відтінки почуттів
Я з тобою розділив...
І тиша може розповісти
Про тебе так багато істин...

Приспів:
І моє море                |
Хвилюється раз...         |
І моє море                |
Хвилюється два...         |
І моє море, нескорене,    |
Б''ється об берег штормами |
Там, де я, там, де ти...  | (2)

Іноді я думаю:
А, може, час піти,
Чи все забути,
Щоб почати все з нуля,
А краще голос твій,
Щоб повернути...
Все залишимо як є,
Все моє і все твоє,
Та тиша може розповісти
Про тебе так багато істин...

Приспів. (2)

І моє море, нескорене,
Б''ється об берег штормами
Там, де я, там, де ти...','[''pisni.org.ua'', ''cat:nostalgia'', ''Пісні з ностальгічними мотивами'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4351430'), datetime('now')),datetime('now'));
